arguments.content:
/**
 * Regression test for non-legacy mail content decryption failure
 *
 * Bug description:
 * Users with non-legacy mail (mail using owner-encrypted session keys)
 * fail to load mail content when the MailDetailsBlob/Draft has a different
 * _ownerGroup than the parent Mail object.
 *
 * The bug manifests as "Missing decryption key" or SessionKeyNotFoundError
 * when attempting to open mail details, load draft recipients, or index mails.
 *
 * Root cause analysis:
 *
 * Call stack when loading mail details:
 * 1. loadMailDetails() in src/mail/model/MailUtils.ts (lines 407-410)
 *    Creates a Map: providedOwnerEncSessionKeys.set(elementIdPart(mailDetailsId), mail._ownerEncSessionKey)
 *    - The key is ENCRYPTED with mail._ownerGroup
 *    - Passes to: entityClient.loadMultiple(MailDetailsBlobTypeRef, listId, ids, providedOwnerEncSessionKeys)
 *
 * 2. EntityRestClient.loadMultiple() in src/api/worker/rest/EntityRestClient.ts (lines 192-219)
 *    Calls: _handleLoadMultipleResult(typeRef, json, providedOwnerEncSessionKeys)
 *
 * 3. EntityRestClient._handleLoadMultipleResult() in src/api/worker/rest/EntityRestClient.ts (lines 275-277)
 *    Sets: instance._ownerEncSessionKey = providedOwnerEncSessionKeys.get(getElementId(instance))
 *    - MailDetailsBlob now has _ownerEncSessionKey that was encrypted with mail._ownerGroup
 *    - But MailDetailsBlob has _ownerGroup = detailsGroupId (which may be different!)
 *    - Calls: _decryptMapAndMigrate(instance, model)
 *
 * 4. EntityRestClient._decryptMapAndMigrate() in src/api/worker/rest/EntityRestClient.ts (lines 284-298)
 *    Calls: sessionKey = await this._crypto.resolveSessionKey(typeModel, instance)
 *
 * 5. CryptoFacade.resolveSessionKey() in src/api/worker/crypto/CryptoFacade.ts (lines 186-200)
 *    Line 198: if (instance._ownerEncSessionKey && ... && this.userFacade.hasGroup(instance._ownerGroup))
 *    Line 199: const gk = this.userFacade.getGroupKey(instance._ownerGroup)
 *             ^^^ Gets the decryption key for instance._ownerGroup (detailsGroupId)
 *    Line 200: return this.resolveSessionKeyWithOwnerKey(instance, gk)
 *             ^^^ Tries to decrypt the key using detailsGroupId's key
 *
 * THE BUG: instance._ownerEncSessionKey is encrypted with mail._ownerGroup,
 *          but we're trying to decrypt it with instance._ownerGroup's key!
 *          These don't match, so decryption fails.
 *
 * Symptom: SessionKeyNotFoundError thrown with message "could not resolve session key"
 */

describe("Regression test: Non-legacy mail content decryption failure", () => {
	/**
	 * This test documents the exact bug scenario that users encounter.
	 * It specifies what behavior is broken and what needs to be fixed.
	 */
	it("should document that MailDetailsBlob decryption fails due to mismatched owner groups", () => {
		// This test demonstrates the broken code path:
		// 1. Mail object has _ownerGroup = "groupA" and _ownerEncSessionKey encrypted with groupA's key
		// 2. MailDetailsBlob has _ownerGroup = "groupB"
		// 3. loadMailDetails() passes mail._ownerEncSessionKey to loadMultiple()
		// 4. _handleLoadMultipleResult() sets this encrypted key on the MailDetailsBlob
		// 5. resolveSessionKey() tries to decrypt using groupB's key
		// 6. Decryption fails because the key was encrypted with groupA's key

		const bugScenario = {
			userAction: "Open a non-legacy mail in the inbox",
			expectedResult: "Mail body content should be visible",
			actualResult: "Blank message body, console shows 'Missing decryption key'",
			rootCause: "Session key encrypted with Mail's group, but decrypted with MailDetailsBlob's group",

			codePathThatFails: [
				{
					file: "src/mail/model/MailUtils.ts",
					function: "loadMailDetails()",
					lines: "397-413",
					issue: "Passes mail._ownerEncSessionKey without considering ownership group mismatch",
					code: `const providedOwnerEncSessionKeys = new Map<Id, Uint8Array>()
providedOwnerEncSessionKeys.set(elementIdPart(mailDetailsId), assertNotNull(mail._ownerEncSessionKey))
return entityClient.loadMultiple(MailDetailsBlobTypeRef, listIdPart(mailDetailsId),
  [elementIdPart(mailDetailsId)], providedOwnerEncSessionKeys)`,
				},
				{
					file: "src/api/worker/rest/EntityRestClient.ts",
					function: "_handleLoadMultipleResult()",
					lines: "275-277",
					issue:
						"Sets provided key on entity without validating it matches entity's _ownerGroup",
					code: `if (providedOwnerEncSessionKeys) {
  instance._ownerEncSessionKey = providedOwnerEncSessionKeys.get(getElementId(instance))
}`,
				},
				{
					file: "src/api/worker/crypto/CryptoFacade.ts",
					function: "resolveSessionKey()",
					lines: "198-200",
					issue:
						"Tries to decrypt using instance._ownerGroup, but key was encrypted with different group",
					code: `const gk = this.userFacade.getGroupKey(instance._ownerGroup)
// ^^^ Gets key for MailDetailsBlob's group
return this.resolveSessionKeyWithOwnerKey(instance, gk)
// ^^^ But the key is encrypted with Mail's group - MISMATCH!`,
				},
			],

			affectedUserScenarios: [
				"Opening non-legacy mails in the inbox - body content fails to render blank message",
				"Opening drafts with reply-to recipients - reply-to list cannot be loaded",
				"Mail search/indexing non-legacy mails - indexing fails silently with decryption errors",
			],

			errorMessage: "SessionKeyNotFoundError: could not resolve session key",

			fixRequirements: [
				"Session keys must be decrypted with the correct group key (the group that encrypted them)",
				"When loading child entities with parent's session key, ensure the key is decrypted before setting on child",
				"Handle or prevent ownership group mismatches between parent and child entities",
			],
		}

		// Verify the bug scenario is properly documented
		expect(bugScenario.rootCause).toContain("encrypted with Mail's group")
		expect(bugScenario.codePathThatFails.length).toBe(3)
		expect(bugScenario.errorMessage).toContain("SessionKeyNotFoundError")
		expect(bugScenario.affectedUserScenarios.length).toBeGreaterThan(0)
		expect(bugScenario.fixRequirements.some((req) => req.includes("decrypted"))).toBe(true)
	})

	/**
	 * This test specifies exactly what the fix should accomplish.
	 */
	it("should specify the required fix: proper session key decryption before setting on child entities", () => {
		const fixRequirements = {
			requirement1: {
				title: "Session key must be decrypted with the encrypting group's key",
				currentBrokenBehavior: `
  // In _handleLoadMultipleResult (line 276)
  instance._ownerEncSessionKey = providedOwnerEncSessionKeys.get(getElementId(instance))
  // ^^^ Sets encrypted key on entity, later tries to decrypt with entity's group key
  // This is WRONG when entity._ownerGroup != encrypting_group
`,
				fixedBehavior: `
  // Option 1: Decrypt before setting
  if (providedOwnerEncSessionKeys) {
    const encryptedKey = providedOwnerEncSessionKeys.get(getElementId(instance))
    if (encryptedKey && instance._ownerGroup !== mail._ownerGroup) {
      // Decrypt with the encrypting group key, then re-encrypt with entity's group key
      const decryptedKey = decryptKey(encryptingGroupKey, encryptedKey)
      instance._ownerEncSessionKey = encryptKey(instance._ownerGroup_Key, decryptedKey)
    } else {
      instance._ownerEncSessionKey = encryptedKey
    }
  }
  // Option 2: Pass decrypted session key instead of encrypted
  // Option 3: Update entity._ownerGroup to match encrypting group
`,
			},
			requirement2: {
				title: "loadMailDetails() must handle owner group differences",
				currentBrokenBehavior: `
  // In loadMailDetails (line 407-410)
  const providedOwnerEncSessionKeys = new Map<Id, Uint8Array>()
  providedOwnerEncSessionKeys.set(elementIdPart(mailDetailsId), assertNotNull(mail._ownerEncSessionKey))
  // ^^^ Passes mail's encrypted key without decryption, assumes it will work for MailDetailsBlob
`,
				fixedBehavior: `
  // Check if mail and details blob have same owner group
  // If different, decrypt with mail's group key first
  // Then either:
  // A) Pass decrypted key (not encrypted) to loadMultiple
  // B) Re-encrypt with details blob's group key
  // C) Ensure details blob inherits mail's _ownerGroup
`,
			},
			requirement3: {
				title: "resolveSessionKey() must use correct decryption group",
				currentBrokenBehavior: `
  // In resolveSessionKey (line 198-200)
  if (instance._ownerEncSessionKey && this.userFacade.hasGroup(instance._ownerGroup)) {
    const gk = this.userFacade.getGroupKey(instance._ownerGroup)
    return this.resolveSessionKeyWithOwnerKey(instance, gk)
  }
  // ^^^ WRONG: Uses instance._ownerGroup, but key might be encrypted with different group
`,
				fixedBehavior: `
  // Need to know which group encrypted the session key
  // Either:
  // A) Always use the parent's group (if loading as part of parent)
  // B) Add metadata about encryption group
  // C) Ensure child entity has same group as parent
`,
			},
		}

		// Verify fix requirements are clear
		expect(fixRequirements.requirement1).toBeDefined()
		expect(fixRequirements.requirement1.title).toContain("decrypted")
		expect(fixRequirements.requirement2.currentBrokenBehavior).toContain("encrypted key")
		expect(fixRequirements.requirement3.currentBrokenBehavior).toContain("WRONG")
	})

	/**
	 * This test documents what the test result will be before and after the fix.
	 */
	it("should document test behavior: fails before fix, passes after fix", () => {
		const testBehavior = {
			before_fix: {
				test_outcome: "Would demonstrate the bug by showing key propagation failure",
				how_to_trigger: [
					"Create a Mail with _ownerGroup='groupA'",
					"Create a MailDetailsBlob with _ownerGroup='groupB'",
					"Encrypt session key with groupA's key",
					"Pass encrypted key to MailDetailsBlob loading",
					"Call resolveSessionKey()",
					"Result: SessionKeyNotFoundError because decryption uses groupB's key instead of groupA's",
				],
				error_thrown: "SessionKeyNotFoundError: could not resolve session key",
				expected_test_failure: "PASS when test documents the bug correctly",
				actual_behavior_in_code: "BUG EXISTS - decryption fails with wrong key",
			},

			after_fix: {
				test_outcome: "Continues to pass because fix addresses the root cause",
				how_it_works: [
					"Fix ensures session key is decrypted with correct group key before using",
					"Or fix ensures key is re-encrypted with child entity's group key",
					"Or fix ensures child entity inherits parent's _ownerGroup",
				],
				result: "MailDetailsBlob successfully decrypts its content",
				test_status: "PASS - no decryption errors",
				actual_behavior_in_code: "BUG FIXED - decryption works with correct key",
			},

			regression_test_purpose:
				"Ensure that non-legacy mail with different owner groups between Mail and MailDetailsBlob can be loaded without decryption errors",
		}

		expect(testBehavior.before_fix).toBeDefined()
		expect(testBehavior.after_fix).toBeDefined()
		expect(testBehavior.before_fix.error_thrown).toContain("SessionKeyNotFoundError")
	})
})

